    def _parse_gcs_path(self, gcs_path):
        """
        Parses a GCS path into bucket name and blob prefix.

        Args:
            gcs_path (str): The full GCS path (e.g., "gs://my-bucket/models/my-model").

        Returns:
            tuple: A tuple containing (bucket_name, blob_prefix).

        Raises:
            ValueError: If the GCS path is invalid.
        """
        parsed_url = urlparse(gcs_path)
        if parsed_url.scheme != 'gs' or not parsed_url.netloc:
            raise ValueError(f"Invalid GCS path format: {gcs_path}. Expected 'gs://bucket-name/path/to/model'.")
        bucket_name = parsed_url.netloc
        blob_prefix = parsed_url.path.lstrip('/')
        return bucket_name, blob_prefix

    def _get_latest_model_blob(self, bucket_name, model_prefix):
        """
        Finds the latest version of a model within a GCS prefix based on creation time.

        Args:
            bucket_name (str): The name of the GCS bucket.
            model_prefix (str): The GCS prefix where model versions are stored
                                (e.g., "models/my-model").

        Returns:
            google.cloud.storage.blob.Blob: The latest model blob, or None if no models found.
        """
        bucket = self.gcs_client.bucket(bucket_name)
        blobs = list(bucket.list_blobs(prefix=model_prefix))

        if not blobs:
            logging.warning(f"No blobs found under prefix: gs://{bucket_name}/{model_prefix}")
            return None

        # Filter out directories and non-model files if necessary,
        # but for simplicity, we assume all blobs under the prefix are part of a model version.
        # The "latest" is determined by the creation timestamp of the *first* file in a version directory.
        # A more robust approach might involve a specific naming convention or metadata.

        # Group blobs by their "version" directory (e.g., models/my-model/v1/, models/my-model/v2/)
        # and find the latest version directory.
        version_dirs = {}
        for blob in blobs:
            # Example: model_prefix = 'models/my-model'
            # blob.name = 'models/my-model/v1/model.pkl'
            # relative_path = 'v1/model.pkl'
            relative_path = os.path.relpath(blob.name, model_prefix)
            if '/' in relative_path:
                version_dir = relative_path.split('/')[0]
                full_version_prefix = os.path.join(model_prefix, version_dir)
                if full_version_prefix not in version_dirs:
                    # Store the first blob found for this version directory to get its creation time
                    version_dirs[full_version_prefix] = blob

        if not version_dirs:
            logging.warning(f"No distinct model versions found under prefix: gs://{bucket_name}/{model_prefix}")
            return None

        # Find the version directory with the latest creation time
        latest_version_prefix = None
        latest_creation_time = None

        for version_prefix, representative_blob in version_dirs.items():
            if latest_creation_time is None or representative_blob.time_created > latest_creation_time:
                latest_creation_time = representative_blob.time_created
                latest_version_prefix = version_prefix

        if latest_version_prefix:
            logging.info(f"Identified latest model version directory: {latest_version_prefix} (created: {latest_creation_time})")
            # Now list all blobs within this latest version directory
